import React, { useState } from 'react';
import { useAuth } from '../auth/AuthContext';
import { apiRequest } from '../api/client';

function AdminPage() {
  const { token, setFlash } = useAuth();
  const [users, setUsers] = useState([]);
  const [analytics, setAnalytics] = useState(null);

  async function loadUsers() {
    try {
      const data = await apiRequest('/admin/users?page=1&page_size=50', { token });
      setUsers(data.items || []);
      setFlash({ type: 'success', text: `Loaded ${data.items?.length || 0} users.` });
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    }
  }

  async function loadAnalytics() {
    try {
      const data = await apiRequest('/admin/analytics', { token });
      setAnalytics(data);
      setFlash({ type: 'success', text: 'Analytics loaded.' });
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    }
  }

  async function verifyUser(userId, verified) {
    const notes = window.prompt('Add verification note', verified ? 'Approved' : 'Rejected');
    if (!notes) {
      return;
    }

    try {
      await apiRequest(`/admin/verify-user/${userId}`, {
        method: 'POST',
        token,
        body: { verified, notes },
      });
      setFlash({ type: 'success', text: `Verification updated for user ${userId}.` });
      await loadUsers();
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    }
  }

  async function blockUser(userId) {
    const reason = window.prompt('Block reason', 'Policy violation');
    if (!reason) {
      return;
    }

    try {
      await apiRequest(`/admin/block-user/${userId}`, {
        method: 'POST',
        token,
        body: { reason, details: reason },
      });
      setFlash({ type: 'success', text: `User ${userId} blocked.` });
      await loadUsers();
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    }
  }

  return (
    <section className="panel full">
      <h2>Admin Console</h2>

      <div className="tab-row">
        <button onClick={loadAnalytics}>Load Analytics</button>
        <button onClick={loadUsers}>Load Users</button>
      </div>

      {analytics && (
        <div className="kpi-grid top-space">
          <div className="kpi">
            <h3>Total Requests</h3>
            <p>{analytics.metrics.total_requests}</p>
          </div>
          <div className="kpi">
            <h3>Total Matches</h3>
            <p>{analytics.metrics.total_matches}</p>
          </div>
          <div className="kpi">
            <h3>Success Rate</h3>
            <p>{analytics.metrics.match_success_rate}%</p>
          </div>
          <div className="kpi">
            <h3>Total Donors</h3>
            <p>{analytics.metrics.total_donors}</p>
          </div>
        </div>
      )}

      <div className="list-block">
        <h3>User Governance</h3>
        {users.map((user) => (
          <div key={user.user_id} className="list-item multi">
            <div>
              {user.user_id} | {user.email} | {user.role} | verified: {String(user.id_verified)} | blocked: {String(user.is_blocked)}
            </div>
            <div className="tab-row">
              <button onClick={() => verifyUser(user.user_id, true)}>Verify</button>
              <button onClick={() => verifyUser(user.user_id, false)}>Reject</button>
              <button className="danger" onClick={() => blockUser(user.user_id)}>Block</button>
            </div>
          </div>
        ))}
      </div>
    </section>
  );
}

export default AdminPage;
